@app.route('/api/auth/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    email = data.get('email', '').strip()
    full_name = data.get('full_name', '').strip()

    if not validate_username(username):
        return jsonify({'error': 'Invalid username. Use 3-30 alphanumeric characters or underscores.'}), 400

    if not password or len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    if not validate_email(email):
        return jsonify({'error': 'Invalid email format'}), 400

    db = get_db()

    # Check if user already exists
    existing_user = db.users.find_one({'$or': [{'username': username}, {'email': email}]})
    if existing_user:
        return jsonify({'error': 'Username or email already exists'}), 409

    salt, pw_hash = hash_password(password)

    user_doc = {
        'username': username,
        'email': email,
        'full_name': full_name,
        'password_hash': pw_hash,
        'password_salt': salt,
        'role': 'user',
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'is_active': True
    }

    result = db.users.insert_one(user_doc)
    token = generate_token(result.inserted_id, username, 'user')

    return jsonify({
        'message': 'User registered successfully',
        'user_id': str(result.inserted_id),
        'token': token
    }), 201


@app.route('/api/auth/login', methods=['POST'])
def login():
    """Authenticate a user and return a token."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    db = get_db()
    user = db.users.find_one({'username': username, 'is_active': True})

    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401

    if not verify_password(password, user['password_salt'], user['password_hash']):
        return jsonify({'error': 'Invalid credentials'}), 401

    token = generate_token(user['_id'], user['username'], user['role'])

    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user_id': str(user['_id']),
        'role': user['role']
    }), 200


