@app.route('/api/documents', methods=['POST'])
@token_required
def create_document():
    """Create a new document."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    title = data.get('title', '').strip()
    content = data.get('content', '').strip()
    category = data.get('category', '').strip()
    tags = data.get('tags', [])
    status = data.get('status', 'draft')

    if not title or len(title) < 1 or len(title) > 200:
        return jsonify({'error': 'Title is required (1-200 characters)'}), 400

    if status not in ('draft', 'published', 'archived'):
        return jsonify({'error': 'Invalid status'}), 400

    if not isinstance(tags, list):
        return jsonify({'error': 'Tags must be a list'}), 400

    # Sanitize tags
    tags = [sanitize_input(str(tag).strip()) for tag in tags if isinstance(tag, str) and tag.strip()]

    db = get_db()
    document = {
        'title': title,
        'content': content,
        'category': sanitize_input(category),
        'tags': tags,
        'status': status,
        'author_id': ObjectId(g.current_user['user_id']),
        'author_username': g.current_user['username'],
        'created_at': datetime.utcnow(),
        'updated_at': datetime.utcnow(),
        'views': 0,
        'likes': 0
    }

    result = db.documents.insert_one(document)

    return jsonify({
        'message': 'Document created successfully',
        'document_id': str(result.inserted_id)
    }), 201


@app.route('/api/documents', methods=['GET'])
@token_required
def get_documents():
    """Query documents with filtering, sorting, and pagination."""
    db = get_db()

    page = max(1, request.args.get('page', 1, type=int))
    per_page = min(100, max(1, request.args.get('per_page', 20, type=int)))
    skip = (page - 1) * per_page

    # Build query filter from allowed parameters only
    query = {}

    status = request.args.get('status')
    if status and status in ('draft', 'published', 'archived'):
        query['status'] = status
    elif g.current_user.get('role') != 'admin':
        # Non-admins can only see published documents or their own
        query['$or'] = [
            {'status': 'published'},
            {'author_id': ObjectId(g.current_user['user_id'])}
        ]

    category = request.args.get('category')
    if category and isinstance(category, str):
        query['category'] = sanitize_input(category.strip())

    tag = request.args.get('tag')
    if tag and isinstance(tag, str):
        query['tags'] = sanitize_input(tag.strip())

    author = request.args.get('author')
    if author and isinstance(author, str):
        query['author_username'] = sanitize_input(author.strip())

    search = request.args.get('search')
    if search and isinstance(search, str):
        # Use text search safely - escape regex special characters
        escaped_search = re.escape(sanitize_input(search.strip()))
        query['$or'] = [
            {'title': {'$regex': escaped_search, '$options': 'i'}},
            {'content': {'$regex': escaped_search, '$options': 'i'}}
        ]

    # Sorting
    sort_field = request.args.get('sort', 'created_at')
    sort_order = -1 if request.args.get('order', 'desc') == 'desc' else 1

    allowed_sort_fields = {'created_at', 'updated_at', 'title', 'views', 'likes'}
    if sort_field not in allowed_sort_fields:
        sort_field = 'created_at'

    documents = list(db.documents.find(query).sort(sort_field, sort_order).skip(skip).limit(per_page))
    total = db.documents.count_documents(query)

    return jsonify({
        'documents': loads(dumps(documents)),
        'total': total,
        'page': page,
        'per_page': per_page,
        'total_pages': (total + per_page - 1) // per_page
    }), 200


